    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u64);
} counter SEC(".maps");
struct {
    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u32); /* target tgid */
} cfg SEC(".maps");
const char expected_str[] = "ok";
SEC("tracepoint/syscalls/sys_enter_openat")
int helper_arg_decrease(struct trace_event_raw_sys_enter *ctx)
{
    __u32 key = 0;
    __u64 *val = bpf_map_lookup_elem(&counter, &key);
    __u32 *target_tgid = bpf_map_lookup_elem(&cfg, &key);
    const char s1[] = "ok";
    long ret = 0;
    int i;
    if (!val)
        return 0;
    if (target_tgid && *target_tgid) {
        __u32 tgid = (__u32)(bpf_get_current_pid_tgid() >> 32);
        if (tgid != *target_tgid)
            return 0;
    }
    /* Crutial block */
    #pragma unroll
    for (i = 0; i < sizeof(s1); i++) {
        if (s1[i] == '\0' && expected_str[i] == '\0') {
            ret = 0;
            break;
        }
        if (s1[i] != expected_str[i]) {
            ret = (long)s1[i] - (long)expected_str[i];
            break;
        }
    }
    /* Crutial block end */
    if (ret == 0)
        (*val)++;
    return 0;
}
